const marketData = $json;
const ctx = $('Config').item.json;
const symbol = ctx.symbol;

const systemPrompt = `Eres el modulo de decision de un bot de grid trading en Binance Futures.
Recibes datos de mercado ya calculados (no los recalcules). Tu unica tarea es decidir si conviene lanzar un grid ahora y con que parametros.

Reglas de criterio:
- Si atr_pct (ATR/current_price) es muy bajo (<0.3%), el rango sera demasiado angosto para capturar movimiento -> considera no lanzar.
- Si atr_pct es muy alto (>2%), el mercado puede estar en tendencia fuerte, no lateral -> los grids funcionan peor -> considera no lanzar o reducir gridCount.
- gridCount razonable: entre 5 y 20 segun el ATR. Ejemplo: si atr_pct ~0.5%, usa 10-15 levels. Si atr_pct ~1.5%, usa 8-12 levels.
- Siempre explica tu razonamiento en el campo reasoning ANTES de fijar launch.
- lowerLimit/upperLimit: puedes ajustar los suggested_* si tienes razon fundamental, pero generalmente respeta los sugeridos.
- Si launch=false, devuelve lowerLimit, upperLimit y gridCount como null.

Responde UNICAMENTE en JSON valido, sin texto adicional.`;

const geminiRequestBody = {
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: JSON.stringify(marketData) }] }],
  generationConfig: {
    temperature: 0.4,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        reasoning: { type: 'STRING' },
        launch: { type: 'BOOLEAN' },
        lowerLimit: { type: 'NUMBER', nullable: true },
        upperLimit: { type: 'NUMBER', nullable: true },
        gridCount: { type: 'INTEGER', nullable: true }
      },
      required: ['reasoning', 'launch', 'lowerLimit', 'upperLimit', 'gridCount']
    }
  }
};

return {
  json: {
    geminiRequestBody,
    symbol,
    suggested_quantity_per_order: marketData.suggested_quantity_per_order,
    atr_period: ctx.atr_period,
    atr_multiplier: ctx.atr_multiplier,
    klines_interval: ctx.klines_interval
  }
};

const geminiResponse = $json;
const rawText = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text;
if (!rawText) {
  throw new Error('Respuesta de Gemini sin contenido de texto: ' + JSON.stringify(geminiResponse));
}

let decision;
try {
  decision = JSON.parse(rawText);
} catch (e) {
  throw new Error('No se pudo parsear JSON de Gemini: ' + rawText);
}

const ctx = $('Build Gemini Request').item.json;

return {
  json: {
    symbol: ctx.symbol,
    reasoning: decision.reasoning,
    launch: decision.launch === true,
    lowerLimit: decision.lowerLimit,
    upperLimit: decision.upperLimit,
    gridCount: decision.gridCount,
    suggested_quantity_per_order: ctx.suggested_quantity_per_order,
    atr_period: ctx.atr_period,
    atr_multiplier: ctx.atr_multiplier,
    klines_interval: ctx.klines_interval
  }
};

const resp = $json;
const statusCode = resp.statusCode;
const body = resp.body || {};
const decisionCtx = $('Parse AI Decision').item.json;

if (statusCode === 200) {
  return { json: { isError: false, alreadyExists: false, grid: body, symbol: decisionCtx.symbol, reasoning: decisionCtx.reasoning } };
}

const detailRaw = body.detail !== undefined ? body.detail : body;
const detail = typeof detailRaw === 'string' ? detailRaw : JSON.stringify(detailRaw);

if (statusCode === 400 && detail.toLowerCase().includes('already exists')) {
  return { json: { isError: false, alreadyExists: true, grid: null, symbol: decisionCtx.symbol, reasoning: decisionCtx.reasoning, detail } };
}

return { json: { isError: true, alreadyExists: false, grid: null, symbol: decisionCtx.symbol, reasoning: decisionCtx.reasoning, statusCode, detail } };
